import{_ as i,o as a,c as l,ae as o}from"./chunks/framework.RRduUuAx.js";const h=JSON.parse('{"title":"Merged Fragmented Markdown","description":"","frontmatter":{},"headers":[],"relativePath":"fragemented/plans/merged.md","filePath":"fragemented/plans/merged.md"}'),r={name:"fragemented/plans/merged.md"};function t(n,e,d,c,s,u){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="merged-fragmented-markdown" tabindex="-1">Merged Fragmented Markdown <a class="header-anchor" href="#merged-fragmented-markdown" aria-label="Permalink to &quot;Merged Fragmented Markdown&quot;">​</a></h1><h2 id="source-plans-index-md" tabindex="-1">Source: plans/INDEX.md <a class="header-anchor" href="#source-plans-index-md" aria-label="Permalink to &quot;Source: plans/INDEX.md&quot;">​</a></h2><h1 id="consolidated-index" tabindex="-1">Consolidated Index <a class="header-anchor" href="#consolidated-index" aria-label="Permalink to &quot;Consolidated Index&quot;">​</a></h1><h2 id="files" tabindex="-1">Files <a class="header-anchor" href="#files" aria-label="Permalink to &quot;Files&quot;">​</a></h2><ul><li><code>INDEX.md</code></li><li><code>UNIFIED_E2E_EXECUTION_PLAN.md</code></li><li><code>UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md</code></li></ul><h2 id="subdirectories" tabindex="-1">Subdirectories <a class="header-anchor" href="#subdirectories" aria-label="Permalink to &quot;Subdirectories&quot;">​</a></h2><hr><h2 id="source-plans-unified-e2e-execution-plan-md" tabindex="-1">Source: plans/UNIFIED_E2E_EXECUTION_PLAN.md <a class="header-anchor" href="#source-plans-unified-e2e-execution-plan-md" aria-label="Permalink to &quot;Source: plans/UNIFIED_E2E_EXECUTION_PLAN.md&quot;">​</a></h2><h1 id="unified-e2e-execution-plan" tabindex="-1">Unified E2E Execution Plan <a class="header-anchor" href="#unified-e2e-execution-plan" aria-label="Permalink to &quot;Unified E2E Execution Plan&quot;">​</a></h1><p>Date: 2026-02-21</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Deliver a production-ready local-first analytics pipeline with extension-ready UX integration and governance-grade artifacts.</p><h2 id="phase-plan" tabindex="-1">Phase Plan <a class="header-anchor" href="#phase-plan" aria-label="Permalink to &quot;Phase Plan&quot;">​</a></h2><h2 id="phase-0-contracts-and-baselines" tabindex="-1">Phase 0: Contracts and Baselines <a class="header-anchor" href="#phase-0-contracts-and-baselines" aria-label="Permalink to &quot;Phase 0: Contracts and Baselines&quot;">​</a></h2><ol><li>Freeze normalized event schema and UI snapshot schema.</li><li>Add schema version fields to exported artifacts.</li><li>Lock benchmark correctness golden baselines.</li></ol><p>Exit criteria:</p><ul><li>Contract docs and tests exist,</li><li>schema changes require explicit migration notes.</li></ul><h2 id="phase-1-adapter-hardening" tabindex="-1">Phase 1: Adapter Hardening <a class="header-anchor" href="#phase-1-adapter-hardening" aria-label="Permalink to &quot;Phase 1: Adapter Hardening&quot;">​</a></h2><ol><li>Implement true Cursor SQLite adapter using table-level queries.</li><li>Keep best-effort JSON extraction as fallback with telemetry.</li><li>Expand provider conformance fixtures/tests.</li></ol><p>Exit criteria:</p><ul><li>Cursor DB fixtures parse deterministically,</li><li>adapter test matrix covers all providers.</li></ul><h2 id="phase-2-cache-layer-disk-backed" tabindex="-1">Phase 2: Cache Layer (Disk-backed) <a class="header-anchor" href="#phase-2-cache-layer-disk-backed" aria-label="Permalink to &quot;Phase 2: Cache Layer (Disk-backed)&quot;">​</a></h2><ol><li>Add parsed-event cache keyed by source fingerprint.</li><li>Add aggregate cache keyed by month/filter/pricing hash.</li><li>Add cache metrics (hit/miss, invalidate counts).</li></ol><p>Exit criteria:</p><ul><li>warm runs materially faster than cold,</li><li>correctness equivalent to uncached path.</li></ul><h2 id="phase-3-ui-ux-integration" tabindex="-1">Phase 3: UI/UX Integration <a class="header-anchor" href="#phase-3-ui-ux-integration" aria-label="Permalink to &quot;Phase 3: UI/UX Integration&quot;">​</a></h2><ol><li>Stabilize <code>ui-snapshot</code> schema and document compatibility policy.</li><li>Add optional compact/extended snapshot modes.</li><li>Provide extension integration examples (CodexBar/OpenCode style).</li></ol><p>Exit criteria:</p><ul><li>extension reads file artifact only,</li><li>no additional runtime service required.</li></ul><h2 id="phase-4-governance-ci-gates" tabindex="-1">Phase 4: Governance + CI Gates <a class="header-anchor" href="#phase-4-governance-ci-gates" aria-label="Permalink to &quot;Phase 4: Governance + CI Gates&quot;">​</a></h2><ol><li>Persist per-run pipeline summaries and rolling pointers.</li><li>Enforce pricing audit/lint/check in CI profiles.</li><li>Enforce perf and correctness gates with baseline handling.</li></ol><p>Exit criteria:</p><ul><li>do:all:next outputs complete artifact bundle,</li><li>CI catches correctness/perf regressions.</li></ul><h2 id="phase-5-unified-model-provider-ledger" tabindex="-1">Phase 5: Unified Model + Provider Ledger <a class="header-anchor" href="#phase-5-unified-model-provider-ledger" aria-label="Permalink to &quot;Phase 5: Unified Model + Provider Ledger&quot;">​</a></h2><ol><li>Build deterministic ledger generator from:</li></ol><ul><li><code>pricing.example.json</code></li><li><code>models_normalized.csv</code></li></ul><ol start="2"><li>Emit machine-consumable artifacts:</li></ol><ul><li>unified ledger CSV</li><li>SQL schema</li><li>SQL seed</li></ul><ol start="3"><li>Include mapping provenance:</li></ol><ul><li>provider mapping rule + confidence,</li><li>model mapping rule + confidence,</li><li>benchmark prior coverage stats.</li></ul><ol start="4"><li>Feed cliproxyapi telemetry (Proxyapi adapter) into the same canonical ledger join model.</li></ol><p>Exit criteria:</p><ul><li>unified ledger artifacts regenerate deterministically from one command,</li><li>ledger provides pricing + benchmark priors on one row surface,</li><li>feeder contracts documented for cliproxyapi/OTEL-derived usage.</li></ul><h2 id="work-packages" tabindex="-1">Work Packages <a class="header-anchor" href="#work-packages" aria-label="Permalink to &quot;Work Packages&quot;">​</a></h2><ol><li>WP-A: Cursor SQLite parser module and tests.</li><li>WP-B: Disk cache module + orchestration wiring.</li><li>WP-C: Snapshot schema versioning + extension docs.</li><li>WP-D: Pipeline summary artifact + CI job templates.</li><li>WP-E: Unified provider/model ledger generator + schema/seed governance.</li></ol><h2 id="risks-and-mitigations" tabindex="-1">Risks and Mitigations <a class="header-anchor" href="#risks-and-mitigations" aria-label="Permalink to &quot;Risks and Mitigations&quot;">​</a></h2><ol><li>Provider schema churn:</li></ol><ul><li>Mitigation: versioned adapter mappers + fixture updates.</li></ul><ol start="2"><li>Cache staleness:</li></ol><ul><li>Mitigation: strict fingerprint keys + bypass flag.</li></ul><ol start="3"><li>UI contract drift:</li></ol><ul><li>Mitigation: schema version and compatibility table.</li></ul><ol start="4"><li>Perf false regressions:</li></ol><ul><li>Mitigation: baseline month/workload matching and trend windows.</li></ul><ol start="5"><li>Ledger mapping drift:</li></ol><ul><li>Mitigation: explicit mapping rule/confidence fields and deterministic regeneration from source seeds.</li></ul><h2 id="milestone-acceptance" tabindex="-1">Milestone Acceptance <a class="header-anchor" href="#milestone-acceptance" aria-label="Permalink to &quot;Milestone Acceptance&quot;">​</a></h2><ol><li><code>task do:all:next</code> passes with full artifact outputs.</li><li><code>task orchestrate:ui</code> produces stable snapshot.</li><li>Perf gate and golden correctness checks pass.</li><li>Reconcile summaries are machine-consumable and auditable.</li><li>Unified ledger artifacts exist and validate in SQLite load tests.</li></ol><h2 id="closeout-update-2026-02-21" tabindex="-1">Closeout Update (2026-02-21) <a class="header-anchor" href="#closeout-update-2026-02-21" aria-label="Permalink to &quot;Closeout Update (2026-02-21)&quot;">​</a></h2><p>The following closure items are now completed:</p><ol><li>Normalized event schema contract v1:</li></ol><ul><li><code>docs/contracts/NORMALIZED_EVENT_SCHEMA_CONTRACT_V1.md</code></li></ul><ol start="2"><li>UI snapshot schema contract v1 + compatibility policy:</li></ol><ul><li><code>docs/contracts/UI_SNAPSHOT_SCHEMA_CONTRACT_V1.md</code></li></ul><ol start="3"><li>Extension integration examples for CodexBar/OpenCode-style file reads:</li></ol><ul><li><code>docs/integrations/EXTENSION_FILE_READ_INTEGRATION_EXAMPLES.md</code></li></ul><ol start="4"><li>CI workflow for pricing governance checks:</li></ol><ul><li><code>.github/workflows/pricing-governance-check.yml</code></li><li>runs <code>pricing-lint</code>, <code>pricing-audit</code>, and <code>pricing-check</code></li></ul><ol start="5"><li>Operator shortcuts and docs references:</li></ol><ul><li><code>task pricing:ci</code></li><li><code>cargo run -- pricing-lint --pricing ./pricing.example.json</code></li><li><code>cargo run -- pricing-audit --pricing ./pricing.example.json</code></li><li><code>cargo run -- pricing-check --events ./examples/events.jsonl --pricing ./pricing.example.json --month 2026-02</code></li></ul><h2 id="closeout-batch-cache-layer-operator-wiring-2026-02-21" tabindex="-1">Closeout Batch: Cache-Layer Operator Wiring (2026-02-21) <a class="header-anchor" href="#closeout-batch-cache-layer-operator-wiring-2026-02-21" aria-label="Permalink to &quot;Closeout Batch: Cache-Layer Operator Wiring (2026-02-21)&quot;">​</a></h2><p>The following cache-layer closure items are completed:</p><ol><li>Task wiring for aggregate cache orchestration:</li></ol><ul><li><code>task orchestrate</code>, <code>task orchestrate:ui</code>, and <code>task do:all:next</code> now pass <code>--aggregate-cache-path</code>.</li><li>Added <code>task orchestrate:cache</code> for sample-data aggregate cache warm runs.</li></ul><ol start="2"><li>Cache metrics validation operator task:</li></ol><ul><li>Added <code>task orchestrate:cache:metrics:validate</code>.</li><li>Validates <code>miss -&gt; hit -&gt; invalidate</code> transitions via <code>aggregate_cache</code> metrics in pipeline summaries.</li></ul><ol start="3"><li>README operator command updates:</li></ol><ul><li>Orchestrate command examples now include <code>--aggregate-cache-path</code>.</li></ul><ol start="4"><li>Cache semantics documentation:</li></ol><ul><li>Added cache key and metrics semantics (<code>hit/miss/invalidate</code>) in governance docs.</li></ul><ol start="5"><li>CI cache-path exercise profile:</li></ol><ul><li>Added pricing-governance CI step that runs sample-data orchestrate with aggregate cache and validates cache metrics on second run.</li></ul><h2 id="closeout-batch-baseline-and-contract-guards-2026-02-21" tabindex="-1">Closeout Batch: Baseline and Contract Guards (2026-02-21) <a class="header-anchor" href="#closeout-batch-baseline-and-contract-guards-2026-02-21" aria-label="Permalink to &quot;Closeout Batch: Baseline and Contract Guards (2026-02-21)&quot;">​</a></h2><p>The following governance gaps are now closed:</p><ol><li>Benchmark golden baseline lock procedure:</li></ol><ul><li>Added <code>task bench:golden:lock</code> to regenerate fixture from canonical sample inputs.</li><li>Added <code>task bench:golden:lock:verify</code> to regenerate and immediately verify with <code>--golden</code>.</li></ul><ol start="2"><li>Golden baseline enforcement in CI:</li></ol><ul><li><code>.github/workflows/bench-perf-gate.yml</code> now runs a golden verification step before strict perf-gate checks.</li></ul><ol start="3"><li>Golden fixture strictness hardening:</li></ol><ul><li>runtime verification now fails when golden contains scenarios absent from current report output.</li></ul><ol start="4"><li>Cache contract version guards:</li></ol><ul><li>ingest and aggregate cache loaders ignore/reset stale versioned cache payloads instead of reusing incompatible serialized state.</li></ul><hr><h2 id="source-plans-unified-model-provider-ledger-plan-2026-02-21-md" tabindex="-1">Source: plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md <a class="header-anchor" href="#source-plans-unified-model-provider-ledger-plan-2026-02-21-md" aria-label="Permalink to &quot;Source: plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md&quot;">​</a></h2><h1 id="unified-model-provider-ledger-plan-2026-02-21" tabindex="-1">Unified Model + Provider Ledger Plan (2026-02-21) <a class="header-anchor" href="#unified-model-provider-ledger-plan-2026-02-21" aria-label="Permalink to &quot;Unified Model + Provider Ledger Plan (2026-02-21)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Create one canonical ledger that joins:</p><ol><li>Provider/model pricing data,</li><li>model benchmark priors,</li><li>mapping provenance (rules/confidence),</li><li>runtime telemetry feeder compatibility (including cliproxyapi/OTEL-normalized usage).</li></ol><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><ol><li><code>pricing.example.json</code></li><li><code>models_normalized.csv</code></li><li>Ingested normalized JSONL events (including <code>provider=proxyapi</code>)</li></ol><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><ol><li><code>ledger/unified_model_provider_ledger.csv</code></li><li><code>ledger/unified_model_provider_ledger.schema.sql</code></li><li><code>ledger/unified_model_provider_ledger.seed.sql</code></li></ol><h2 id="generation-pipeline" tabindex="-1">Generation pipeline <a class="header-anchor" href="#generation-pipeline" aria-label="Permalink to &quot;Generation pipeline&quot;">​</a></h2><ol><li>Parse pricing and canonical provider/model maps.</li><li>Parse normalized model benchmark rows.</li><li>Infer provider and canonical model candidates for each source model.</li><li>Attach benchmark priors and pricing deltas.</li><li>Emit CSV + SQL schema + SQL inserts.</li></ol><h2 id="mapping-methodology" tabindex="-1">Mapping methodology <a class="header-anchor" href="#mapping-methodology" aria-label="Permalink to &quot;Mapping methodology&quot;">​</a></h2><ol><li>Provider mapping:</li></ol><ul><li>deterministic token/prefix-based heuristics,</li><li>explicit <code>provider_mapping_rule</code>,</li><li>integer <code>provider_mapping_confidence</code>.</li></ul><ol start="2"><li>Model mapping:</li></ol><ul><li>exact pricing model match first,</li><li>alias/model-family heuristics second,</li><li>explicit <code>model_mapping_rule</code>,</li><li>integer <code>model_mapping_confidence</code>.</li></ul><ol start="3"><li>Unknown/unmapped models:</li></ol><ul><li>retained in output with null pricing,</li><li>benchmark priors preserved for analysis.</li></ul><h2 id="runtime-integration-scope" tabindex="-1">Runtime integration scope <a class="header-anchor" href="#runtime-integration-scope" aria-label="Permalink to &quot;Runtime integration scope&quot;">​</a></h2><ol><li><code>tokenledger ingest --provider proxyapi</code> emits normalized JSONL from cliproxyapi/OTEL and usage payloads.</li><li>Runtime events join to ledger on canonicalized provider/model.</li><li>Blended cost + benchmark-aware Pareto scoring can be computed from unified rows.</li></ol><h2 id="governance" tabindex="-1">Governance <a class="header-anchor" href="#governance" aria-label="Permalink to &quot;Governance&quot;">​</a></h2><ol><li>Ledger artifacts are generated, not manually edited.</li><li>Regeneration command must be deterministic.</li><li>Mapping confidence/rule fields are mandatory for auditability.</li><li>SQL seed must load cleanly in SQLite checks.</li></ol><h2 id="execution-checklist" tabindex="-1">Execution checklist <a class="header-anchor" href="#execution-checklist" aria-label="Permalink to &quot;Execution checklist&quot;">​</a></h2><ol><li>Run generator:</li></ol><ul><li><code>python3 ./scripts/build_unified_ledger.py</code></li></ul><ol start="2"><li>Validate load:</li></ol><ul><li><code>sqlite3 :memory: &quot;.read ./ledger/unified_model_provider_ledger.schema.sql&quot; &quot;.read ./ledger/unified_model_provider_ledger.seed.sql&quot; &quot;SELECT COUNT(*) FROM unified_model_provider_ledger;&quot;</code></li></ul><ol start="3"><li>Validate feeder:</li></ol><ul><li><code>cargo run -- ingest --provider proxyapi --output ./artifacts/proxyapi-events.jsonl</code></li></ul><ol start="4"><li>Validate end-to-end orchestrate:</li></ol><ul><li><code>cargo run -- orchestrate --providers proxyapi --events-out ./artifacts/proxyapi-events.jsonl --summary-json-path ./benchmarks/results/ingest-summary.json --ingest-cache-path ./benchmarks/results/orchestrate-ingest-cache.json --pipeline-summary-path ./benchmarks/results/orchestrate-summary.json --pricing-reconcile-dry-run</code></li></ul><h2 id="closeout-update-2026-02-21-1" tabindex="-1">Closeout update (2026-02-21) <a class="header-anchor" href="#closeout-update-2026-02-21-1" aria-label="Permalink to &quot;Closeout update (2026-02-21)&quot;">​</a></h2><ol><li>ProxyAPI feeder validation taskchain is now explicit and repeatable:</li></ol><ul><li><code>task ingest:proxyapi:validate</code></li><li><code>task orchestrate:proxyapi:validate</code></li><li><code>task ledger:proxyapi:e2e:validate</code> (runs both in sequence)</li></ul><ol start="2"><li>End-to-end orchestrate validation now persists summary artifacts under:</li></ol><ul><li><code>benchmarks/results/proxyapi-ingest-summary.json</code></li><li><code>benchmarks/results/proxyapi-orchestrate-summary.json</code></li><li><code>benchmarks/results/proxyapi-ui-snapshot.json</code></li></ul><hr>',130)])])}const m=i(r,[["render",t]]);export{h as __pageData,m as default};
